function subscribeClientRealtime(){clearClientRealtime();if(!currentGymId||!currentUserId)return;const push=ch=>{clientRealtimeChannels.push(ch);return ch};push(sb.channel(`client-msg-${currentUserId}`).on('postgres_changes',{event:'*',schema:'public',table:'messages',filter:`gym_id=eq.${currentGymId}`},payload=>{const row=payload.new||payload.old||{};if(row.sender_id===currentUserId||row.receiver_id===currentUserId)queueClientReload(200)}).subscribe());push(sb.channel(`client-sessions-${currentUserId}`).on('postgres_changes',{event:'*',schema:'public',table:'sessions',filter:`client_id=eq.${currentUserId}`},()=>queueClientReload(220)).subscribe());push(sb.channel(`client-checkins-${currentUserId}`).on('postgres_changes',{event:'*',schema:'public',table:'check_ins',filter:`client_id=eq.${currentUserId}`},()=>queueClientReload(220)).subscribe());push(sb.channel(`client-plans-${currentUserId}`).on('postgres_changes',{event:'*',schema:'public',table:'workout_plans',filter:`client_id=eq.${currentUserId}`},()=>queueClientReload(260)).subscribe())}
async function loadData(){const assignRes=await Trainw.api.run(sb.from('coach_client_assignments').select('coach_id').eq('client_id',currentUserId).eq('gym_id',currentGymId).eq('is_active',true).limit(1),{context:'load coach assignment',fallback:[]});const assignedCoachId=assignRes.data?.[0]?.coach_id||null;const [profileRes,ownerRes,sessionsRes,planRes,weightRes,goalRes,checkRes,msgRes,coachesRes,reviewsRes]=await Promise.all([Trainw.api.run(sb.from('client_profiles').select('*').eq('user_id',currentUserId).maybeSingle(),{context:'load client profile',fallback:null}),Trainw.api.run(sb.rpc('list_gym_member_directory',{p_gym_id:currentGymId}),{context:'load gym owner',fallback:[]}),Trainw.api.run(sb.from('sessions').select('id,gym_id,session_date,start_time,end_time,duration_minutes,type,status,coach_id,session_name,notes,cancellation_reason,users!sessions_coach_id_fkey(name)').eq('client_id',currentUserId).order('session_date',{ascending:true}).order('start_time',{ascending:true}),{context:'load personal sessions',fallback:[]}),Trainw.api.run(sb.from('workout_plans').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('updated_at',{ascending:false}).limit(1),{context:'load active plan',fallback:[]}),Trainw.api.run(sb.from('weight_logs').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('logged_at',{ascending:false}),{context:'load weight logs',fallback:[]}),Trainw.api.run(sb.from('client_goals').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('created_at',{ascending:false}).limit(1),{context:'load goals',fallback:[]}),Trainw.api.run(sb.from('check_ins').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('checked_in_at',{ascending:false}).limit(60),{context:'load checkins',fallback:[]}),Trainw.api.run(sb.from('messages').select('*').or(`sender_id.eq.${currentUserId},receiver_id.eq.${currentUserId}`).order('created_at',{ascending:false}).limit(200),{context:'load messages',fallback:[]}),Trainw.api.run(sb.from('coach_profiles').select('id,user_id,gym_id,specialty,specialties,price_per_session,hourly_rate,rating,total_reviews,users:users!coach_profiles_user_id_fkey(id,name,phone,gym_id)').eq('gym_id',currentGymId).eq('approval_status','approved').eq('is_active',true).order('rating',{ascending:false}),{context:'load approved coaches',fallback:[]}),loadClientReviews()]);clientProfile=profileRes.data||null;ownerInfo=(ownerRes.data||[]).find(member=>member.portal==='admin'&&['gym_owner','gym_admin'].includes(member.role_code))||null;mySessions=Array.isArray(sessionsRes.data)?sessionsRes.data:[];activePlan=planRes.data?.[0]||null;weightLogs=Array.isArray(weightRes.data)?weightRes.data:[];currentGoal=goalRes.data?.[0]||null;checkins=Array.isArray(checkRes.data)?checkRes.data:[];availableCoaches=Array.isArray(coachesRes.data)?coachesRes.data:[];reviewsBySession=new Map((reviewsRes.data||[]).filter(r=>r.session_id).map(r=>[r.session_id,r]));const primaryCoachId=assignedCoachId||mySessions.find(s=>s.coach_id)?.coach_id||null;if(primaryCoachId){const [coachUser,coachProfile]=await Promise.all([Trainw.api.run(sb.from('users').select('id,name,phone').eq('id',primaryCoachId).maybeSingle(),{context:'load primary coach',fallback:null}),Trainw.api.run(sb.from('coach_profiles').select('specialty').eq('user_id',primaryCoachId).maybeSingle(),{context:'load primary coach profile',fallback:null})]);coachInfo={id:primaryCoachId,name:coachUser.data?.name||'Coach',phone:coachUser.data?.phone||'',specialty:coachProfile.data?.specialty||''}}else coachInfo=null;if(activePlan){const ex=await Trainw.api.run(sb.from('workout_exercises').select('*').eq('plan_id',activePlan.id).order('order_index',{ascending:true}),{context:'load exercises',fallback:[]});planExercises=ex.data||[]}else planExercises=[];workoutLogs=(await Trainw.api.run(sb.from('workout_logs').select('*').eq('client_id',currentUserId).eq('gym_id',currentGymId).order('completed_at',{ascending:false}).limit(10),{context:'load workout logs',fallback:[]})).data||[];logSetsMap=new Map();if(workoutLogs.length){const setRes=await Trainw.api.run(sb.from('workout_log_sets').select('*').in('log_id',workoutLogs.map(x=>x.id)),{context:'load workout log sets',fallback:[]});(setRes.data||[]).forEach(set=>{const arr=logSetsMap.get(set.log_id)||[];arr.push(set);logSetsMap.set(set.log_id,arr)})}const participants=Array.from(new Set([primaryCoachId,ownerInfo?.user_id].filter(Boolean)));threads=participants.map(id=>{const info=id===coachInfo?.id?coachInfo:ownerInfo?{id:ownerInfo.user_id,name:ownerInfo.name||'Contact'}:ownerInfo;const messages=(msgRes.data||[]).filter(m=>m.sender_id===id||m.receiver_id===id).sort((a,b)=>new Date(a.created_at)-new Date(b.created_at));return{id,name:info?.name||'Contact',role:id===coachInfo?.id?t('coachLabel'):t('ownerLabel'),messages}}).filter(x=>x.id);ensureBookingDefaults();await loadBookingSlots(true);renderAll()}
function applyTranslations(){document.documentElement.lang=currentLang;Trainw.applyDocumentLanguage(currentLang,'.app-container');$$('[data-i18n]').forEach(el=>el.textContent=t(el.getAttribute('data-i18n')));$$('[data-i18n-ph]').forEach(el=>el.setAttribute('placeholder',t(el.getAttribute('data-i18n-ph'))));$$('.lang-btn').forEach(b=>b.classList.toggle('active',b.dataset.lang===currentLang))}
function showPage(page){$$('.page').forEach(p=>p.classList.add('hidden'));$('#'+page+'-page')?.classList.remove('hidden');$$('.nav-item').forEach(n=>n.classList.toggle('active',n.dataset.page===page))}
function coachMeta(coach){return t('bookingCoachMeta').replace('{price}',String(Number(coach.price_per_session??coach.hourly_rate??0)||0)).replace('{reviews}',String(coach.total_reviews||0))}
function nextSession(){return[...mySessions].filter(s=>s.status!=='cancelled'&&isFutureSession(s)).sort((a,b)=>sessionAt(a)-sessionAt(b))[0]||null}
function sessionsForDate(dateKey){return[...mySessions].filter(s=>s.session_date===dateKey&&s.status!=='cancelled').sort((a,b)=>sessionAt(a)-sessionAt(b))}
function currentWeight(){return weightLogs[0]?.weight_kg??null}
function startWeight(){return weightLogs[weightLogs.length-1]?.weight_kg??null}
function bookedThisWeek(){const weekStart=new Date();weekStart.setDate(weekStart.getDate()-weekStart.getDay());weekStart.setHours(0,0,0,0);return mySessions.filter(s=>s.status!=='cancelled'&&sessionAt(s)>=weekStart.getTime()).length}
function monthlyCheckins(){const month=new Date().getMonth();return checkins.filter(c=>new Date(c.checked_in_at).getMonth()===month).length}
function activityFeed(){const items=[];mySessions.forEach(s=>items.push({at:s.completed_at||`${s.session_date}T${s.start_time||'00:00:00'}`,title:s.session_name||'Coach session',meta:`${fmtDate(s.session_date)} Â· ${String(s.start_time||'').slice(0,5)} Â· ${bookingMeta(s.status).label}`,tone:'session'}));workoutLogs.forEach(log=>items.push({at:log.completed_at,title:'Workout logged',meta:`${safe(log.duration_minutes)} min Â· RPE ${safe(log.perceived_effort)}`,tone:'workout'}));checkins.forEach(c=>items.push({at:c.checked_in_at,title:'Gym check-in',meta:`${fmtDate(c.checked_in_at)} Â· ${safe(c.method,'manual')}`,tone:'checkin'}));threads.forEach(thread=>{const last=thread.messages[thread.messages.length-1];if(last)items.push({at:last.created_at,title:thread.name||'Conversation',meta:safe(last.content,''),tone:'message'})});return items.filter(item=>item.at).sort((a,b)=>new Date(b.at)-new Date(a.at)).slice(0,6)}
function renderDashboardHero(){const next=nextSession(),membershipDays=clientProfile?.membership_end_date?Math.ceil((new Date(clientProfile.membership_end_date)-new Date())/86400000):null,todayCount=planExercises.filter(x=>weekdayMatch(x.day_label)).length;const focusTitle=next?next.session_name||'Upcoming session':todayCount?'Today\'s plan is ready':'Book your next session';const focusMeta=next?`${fmtDate(next.session_date)} Â· ${String(next.start_time||'').slice(0,5)} Â· ${safe(next.users?.name,'Coach')}`:todayCount?`${todayCount} exercises queued for today`:`${availableCoaches.length} approved coaches available`;let membershipStatus='â€”',membershipCopy='No membership data available.';if(membershipDays!==null){membershipStatus=membershipDays<0?t('membershipExpired'):`${membershipDays}${currentLang==='fr'?'j':'d'}`;membershipCopy=membershipDays<0?t('membershipExpired'):membershipDays<7?t('membershipSoon').replace('{days}',String(membershipDays)):t('membershipActive').replace('{days}',String(membershipDays))}Trainw.ui.setText('dashboard-next-focus',focusTitle);Trainw.ui.setText('dashboard-next-focus-meta',focusMeta);Trainw.ui.setText('dashboard-membership-status',membershipStatus);Trainw.ui.setText('dashboard-membership-copy',membershipCopy)}
function renderDashboardUpcoming(){const upcoming=[...mySessions].filter(s=>s.status!=='cancelled'&&isFutureSession(s)).sort((a,b)=>sessionAt(a)-sessionAt(b)).slice(0,8);$('#dashboard-upcoming-list').innerHTML=upcoming.length?upcoming.map(s=>{const st=bookingMeta(s.status),canCancel=['pending','confirmed'].includes(s.status);return `<article class="session-list-item booking-session-card"><div class="list-item-main"><div class="activity-title">${Trainw.escapeHTML(s.session_name||'Coach session')}</div><div class="activity-meta">${Trainw.escapeHTML(fmtDate(s.session_date))} Â· ${Trainw.escapeHTML(String(s.start_time||'').slice(0,5))} Â· ${Trainw.escapeHTML(safe(s.users?.name,'Coach'))}</div><div class="activity-meta">${Trainw.escapeHTML(t('statusLabel'))}: ${Trainw.escapeHTML(st.label)}</div></div><div class="booking-session-actions"><span class="booking-status-pill ${st.cls}">${Trainw.escapeHTML(st.label)}</span>${canCancel?`<button class="btn-secondary" type="button" data-cancel-session="${s.id}">${Trainw.escapeHTML(t('cancelBooking'))}</button>`:''}</div></article>`}).join(''):`<p class="empty-state">${t('noSessions')}</p>`}
function renderDashboardProgram(){const todayExercises=planExercises.filter(x=>weekdayMatch(x.day_label));$('#dashboard-today-program').innerHTML=todayExercises.length?todayExercises.map(x=>`<div class="today-plan-item"><div><strong>${Trainw.escapeHTML(x.exercise_name)}</strong><div class="activity-meta">${Trainw.escapeHTML(String(safe(x.sets)))} x ${Trainw.escapeHTML(String(safe(x.reps)))} Â· ${Trainw.escapeHTML(String(safe(x.rest_seconds,0)))}s</div></div></div>`).join(''):`<p class="empty-state">${t('noWorkoutToday')}</p>`;$('#btn-start-workout').disabled=!todayExercises.length}
function renderDashboardActivity(){const items=activityFeed();$('#dashboard-recent-activity').innerHTML=items.length?items.map(item=>`<article class="activity-feed-item tone-${item.tone}"><div class="activity-feed-title">${Trainw.escapeHTML(item.title)}</div><div class="activity-feed-meta">${Trainw.escapeHTML(item.meta)}</div><div class="activity-feed-time">${Trainw.escapeHTML(fmtDateTime(item.at))}</div></article>`).join(''):`<p class="empty-state">${t('noData')}</p>`}
function renderDashboardProgress(){const weight=currentWeight(),target=currentGoal?.target_weight_kg??null,daysLeft=currentGoal?.target_date?Math.ceil((new Date(currentGoal.target_date)-new Date())/86400000):null;$('#dashboard-progress-focus').innerHTML=`<div class="mini-metric-grid"><div class="mini-metric-card"><span class="mini-metric-label">Goal</span><strong>${Trainw.escapeHTML(safe(currentGoal?.goal_type,'No goal yet'))}</strong></div><div class="mini-metric-card"><span class="mini-metric-label">Current weight</span><strong>${Trainw.escapeHTML(weight===null?'â€”':`${weight} kg`)}</strong></div><div class="mini-metric-card"><span class="mini-metric-label">Target</span><strong>${Trainw.escapeHTML(target===null?'â€”':`${target} kg`)}</strong></div><div class="mini-metric-card"><span class="mini-metric-label">Time left</span><strong>${Trainw.escapeHTML(daysLeft===null?'â€”':`${daysLeft} ${t('days')}`)}</strong></div></div><div class="summary-note">${Trainw.escapeHTML(currentGoal?.notes||'Set a clear goal to make progress easier to follow.')}</div>`}
function renderDashboardBookingSummary(){const selected=availableCoaches.find(c=>c.user_id===selectedBookingCoachId)||null,bookedCount=sessionsForDate(selectedBookingDate).length,slotSummary=selectedBookingSlot?`${selectedBookingDate} Â· ${selectedBookingSlot}`:'No slot selected yet';$('#dashboard-booking-card').innerHTML=`<div class="summary-stack"><div class="summary-line"><span class="summary-line-label">Coach</span><strong>${Trainw.escapeHTML(selected?.users?.name||'Select a coach')}</strong></div><div class="summary-line"><span class="summary-line-label">Date</span><strong>${Trainw.escapeHTML(selectedBookingDate||'Choose a date')}</strong></div><div class="summary-line"><span class="summary-line-label">Selected slot</span><strong>${Trainw.escapeHTML(slotSummary)}</strong></div><div class="summary-line"><span class="summary-line-label">Booked that day</span><strong>${Trainw.escapeHTML(String(bookedCount))}</strong></div></div>`}
function renderDashboard(){Trainw.ui.setText('stat-checkins',String(monthlyCheckins()));Trainw.ui.setText('stat-sessions',String(bookedThisWeek()));Trainw.ui.setText('stat-streak',String(streak(checkins)));const days=clientProfile?.membership_end_date?Math.ceil((new Date(clientProfile.membership_end_date)-new Date())/86400000):null;Trainw.ui.setText('stat-expiry',days===null?'-':days<0?t('membershipExpired'):String(days));Trainw.ui.setText('stat-expiry-sub',days===null?'-':days<0?t('membershipExpired'):days<7?t('membershipSoon').replace('{days}',String(days)):t('membershipActive').replace('{days}',String(days)));renderDashboardHero();renderDashboardUpcoming();renderDashboardProgram();renderDashboardActivity();renderDashboardProgress();renderDashboardBookingSummary()}
function renderBookingCalendar(){const days=Array.from({length:14},(_,index)=>Trainw.addDays(new Date(),index));$('#booking-calendar-grid').innerHTML=days.map(date=>{const key=Trainw.dateOnly(date),bookedCount=sessionsForDate(key).length,isSelected=key===selectedBookingDate;return `<button class="calendar-day-card ${isSelected?'selected':''} ${bookedCount?'has-bookings':''}" type="button" data-book-date="${key}"><span class="calendar-day-name">${Trainw.escapeHTML(fmtDate(key,{weekday:'short'}))}</span><strong class="calendar-day-number">${date.getDate()}</strong><span class="calendar-day-copy">${Trainw.escapeHTML(bookedCount?`${bookedCount} booked`:'Open')}</span></button>`}).join('')}
function renderBookingDaySessions(){const sessions=sessionsForDate(selectedBookingDate);$('#booking-day-sessions').innerHTML=sessions.length?sessions.map(s=>{const st=bookingMeta(s.status);return `<article class="booking-day-card"><div><div class="activity-title">${Trainw.escapeHTML(s.session_name||'Coach session')}</div><div class="activity-meta">${Trainw.escapeHTML(String(s.start_time||'').slice(0,5))} Â· ${Trainw.escapeHTML(safe(s.users?.name,'Coach'))}</div></div><span class="booking-status-pill ${st.cls}">${Trainw.escapeHTML(st.label)}</span></article>`}).join(''):`<p class="empty-state">No booked sessions for the selected date.</p>`}
function renderBookingConfirmation(){const selected=availableCoaches.find(c=>c.user_id===selectedBookingCoachId)||null,notes=($('#booking-notes-input')?.value||'').trim(),button=$('#btn-book-session');if(!selected||!selectedBookingDate||!selectedBookingSlot){$('#booking-confirmation-card').innerHTML=`<p class="empty-state">${t('bookingNeedsSelection')}</p>`;button.disabled=true;return}$('#booking-confirmation-card').innerHTML=`<div class="confirm-grid"><div class="confirm-item"><span class="confirm-label">Coach</span><strong>${Trainw.escapeHTML(selected.users?.name||'Coach')}</strong></div><div class="confirm-item"><span class="confirm-label">Date</span><strong>${Trainw.escapeHTML(selectedBookingDate)}</strong></div><div class="confirm-item"><span class="confirm-label">Start time</span><strong>${Trainw.escapeHTML(selectedBookingSlot)}</strong></div><div class="confirm-item"><span class="confirm-label">Notes</span><strong>${Trainw.escapeHTML(notes||'No extra notes')}</strong></div></div>`;button.disabled=false}
function renderBookingComposer(){const search=String($('#booking-coach-search')?.value||'').trim().toLowerCase(),list=availableCoaches.filter(c=>!search||[c.users?.name,c.specialty,(c.specialties||[]).join(' ')].map(v=>String(v||'').toLowerCase()).some(v=>v.includes(search))),selected=availableCoaches.find(c=>c.user_id===selectedBookingCoachId)||null,dateInput=$('#booking-date-input');if(dateInput){dateInput.min=Trainw.dateOnly(new Date());dateInput.value=selectedBookingDate}$('#booking-coach-list').innerHTML=list.length?list.map(c=>`<button class="coach-pick-card ${c.user_id===selectedBookingCoachId?'selected':''}" type="button" data-book-coach="${c.user_id}"><div class="coach-pick-avatar">${Trainw.escapeHTML(initials(c.users?.name||'Coach'))}</div><div class="coach-pick-body"><div class="coach-pick-name">${Trainw.escapeHTML(c.users?.name||'Coach')}</div><div class="coach-pick-meta">${Trainw.escapeHTML(c.specialty||(c.specialties||[]).join(', ')||'Coach')}</div><div class="coach-pick-price">${Trainw.escapeHTML(coachMeta(c))}</div></div></button>`).join(''):`<p class="empty-state">${t('noCoachesAvailable')}</p>`;$('#booking-selected-coach').innerHTML=selected?`<div class="booking-selection-title">${Trainw.escapeHTML(selected.users?.name||'Coach')}</div><div class="booking-selection-sub">${Trainw.escapeHTML(coachMeta(selected))}</div><div class="booking-selection-sub">${Trainw.escapeHTML(selected.specialty||(selected.specialties||[]).join(', ')||'')}</div><div class="booking-selection-sub">Selected day: ${Trainw.escapeHTML(selectedBookingDate||'â€”')}</div>`:`<p class="empty-state">${t('chooseCoachFirst')}</p>`;const slotList=$('#booking-slot-list');if(!selectedBookingCoachId)slotList.innerHTML=`<p class="empty-state">${t('chooseCoachFirst')}</p>`;else if(!selectedBookingDate)slotList.innerHTML=`<p class="empty-state">${t('chooseDatePrompt')}</p>`;else if(!bookingSlots.length)slotList.innerHTML=`<p class="empty-state">${t('bookingSlotsEmpty')}</p>`;else slotList.innerHTML=bookingSlots.map(slot=>`<button class="slot ${slot.slot_time===selectedBookingSlot?'selected':''}" type="button" data-slot-time="${slot.slot_time}"><span class="slot-time">${Trainw.escapeHTML(slot.slot_time)}</span><span class="slot-copy">${Trainw.escapeHTML(t('slotUntil').replace('{time}',slot.slot_end_time))}</span></button>`).join('');renderBookingCalendar();renderBookingDaySessions();renderBookingConfirmation()}
function renderPastSessions(){const past=[...mySessions].filter(s=>s.status==='completed'||s.status==='cancelled'||!isFutureSession(s)).sort((a,b)=>sessionAt(b)-sessionAt(a));$('#client-past-sessions-list').innerHTML=past.length?past.map(s=>{const st=bookingMeta(s.status),review=reviewsBySession.get(s.id),draft=reviewDrafts.get(s.id)||{rating:0,comment:''};const reviewBox=review?`<div class="review-box"><div class="goal-item-label">${Trainw.escapeHTML(t('reviewExisting'))}</div><div class="review-copy">${Trainw.escapeHTML(t('reviewRatingLabel'))}: ${Trainw.escapeHTML(String(review.rating))}/5</div><div class="review-copy">${Trainw.escapeHTML(review.comment||'')}</div></div>`:s.status==='completed'?`<div class="review-box"><div class="goal-item-label">${Trainw.escapeHTML(t('reviewTitle'))}</div><div class="review-rating">${[1,2,3,4,5].map(n=>`<button class="review-star ${draft.rating>=n?'active':''}" type="button" data-review-rating="${n}" data-review-session="${s.id}">${n}</button>`).join('')}</div><textarea class="form-input" rows="3" data-review-comment="${s.id}" placeholder="${Trainw.escapeHTML(t('reviewPlaceholder'))}">${Trainw.escapeHTML(draft.comment||'')}</textarea><div class="booking-session-actions"><button class="btn-primary" type="button" data-review-submit="${s.id}">${Trainw.escapeHTML(t('reviewSubmit'))}</button></div></div>`:'';return `<article class="booking-history-card booking-session-card"><div class="booking-session-top"><div><div class="booking-session-title">${Trainw.escapeHTML(s.session_name||'Coach session')}</div><div class="booking-session-meta">${Trainw.escapeHTML(fmtDate(s.session_date))} Â· ${Trainw.escapeHTML(String(s.start_time||'').slice(0,5))} Â· ${Trainw.escapeHTML(safe(s.users?.name,'Coach'))}</div>${s.cancellation_reason?`<div class="booking-session-meta">${Trainw.escapeHTML(s.cancellation_reason)}</div>`:''}</div><span class="booking-status-pill ${st.cls}">${Trainw.escapeHTML(st.label)}</span></div>${reviewBox}</article>`}).join(''):`<p class="empty-state">${t('noBookingHistory')}</p>`}
function planByDay(){const map={};planExercises.forEach(x=>{const k=x.day_label||'Jour';(map[k]=map[k]||[]).push(x)});return Object.entries(map)}
function renderProgram(){const days=planByDay();$('#program-accordion').innerHTML=days.length?days.map(([day,items],i)=>`<article class="program-day-card ${i===0?'open':''}"><div class="program-day-head"><div class="program-day-title">${Trainw.escapeHTML(day)}</div><button class="btn-secondary" data-toggle-day="${i}">+</button></div><div class="program-day-body">${items.map(x=>`<div class="program-ex-row"><strong>${Trainw.escapeHTML(x.exercise_name)}</strong><span>${Trainw.escapeHTML(String(safe(x.sets)))} x ${Trainw.escapeHTML(String(safe(x.reps)))} Â· ${Trainw.escapeHTML(String(safe(x.rest_seconds,0)))}s</span><span>${Trainw.escapeHTML(safe(x.notes,''))}</span></div>`).join('')}</div></article>`).join(''):`<p class="empty-state">${t('noPlan')}</p>`;$('#program-log-list').innerHTML=workoutLogs.length?workoutLogs.map(log=>`<div class="session-list-item"><div><div class="activity-title">${Trainw.escapeHTML(fmtDateTime(log.completed_at))}</div><div class="activity-meta">${Trainw.escapeHTML(String(safe(log.duration_minutes)))} min Â· RPE ${Trainw.escapeHTML(String(safe(log.perceived_effort)))} Â· ${Trainw.escapeHTML(safe(log.notes,''))}</div><div class="activity-meta">${Trainw.escapeHTML((logSetsMap.get(log.id)||[]).map(s=>`${s.exercise_name} ${s.reps_done||'-'}x${s.weight_kg||'-'}`).join(' Â· '))}</div></div><div>${Trainw.renderEffortBar(log.perceived_effort||0)}</div></div>`).join(''):`<p class="empty-state">${t('noData')}</p>`}
function renderWeight(){const ctx=$('#weight-progress-chart');if(ctx&&window.Chart){weightChart?.destroy();const rev=[...weightLogs].reverse();const datasets=[{label:t('weightKg'),data:rev.map(x=>+x.weight_kg||null),borderColor:'#C8F135',backgroundColor:'rgba(200,241,53,.12)',fill:true,tension:.3,borderWidth:3}];if($('#toggle-bodyfat').checked)datasets.push({label:t('bodyFatPct'),data:rev.map(x=>+x.body_fat_pct||null),borderColor:'#3d8eff',borderDash:[8,6],tension:.3,borderWidth:2});weightChart=new Chart(ctx,{type:'line',data:{labels:rev.map(x=>fmtDate(x.logged_at)),datasets},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{color:'#efefef'}}},scales:{x:{ticks:{color:'#888'},grid:{color:'rgba(255,255,255,0.06)'}},y:{ticks:{color:'#888'},grid:{color:'rgba(255,255,255,0.06)'}}}}})}const start=startWeight(),current=currentWeight(),target=currentGoal?.target_weight_kg??null;let pct=0;if(start&&current&&target&&start!==target)pct=Math.max(0,Math.min(100,Math.round(((start-current)/(start-target))*100)));$('#goal-progress-fill').style.width=pct+'%';$('#goal-progress-copy').textContent=target?`${pct}% Â· ${t('targetWeight')}: ${target} kg`:'-';$('#weight-date-input').value=Trainw.dateOnly(new Date());Trainw.ui.setText('weight-metric-start',start===null?'â€”':`${start} kg`);Trainw.ui.setText('weight-metric-current',current===null?'â€”':`${current} kg`);Trainw.ui.setText('weight-metric-change',start!==null&&current!==null?`${(current-start).toFixed(1)} kg`:'â€”');Trainw.ui.setText('weight-metric-target',target===null?'â€”':`${target} kg`);$('#weight-table-wrap').innerHTML=weightLogs.length?`<table><thead><tr><th>${t('dateLabel')}</th><th>${t('weightKg')}</th><th>${t('bodyFatPct')}</th><th>${t('notesLabel')}</th></tr></thead><tbody>${weightLogs.map(w=>`<tr><td>${Trainw.escapeHTML(fmtDate(w.logged_at))}</td><td>${Trainw.escapeHTML(String(safe(w.weight_kg)))}</td><td>${Trainw.escapeHTML(String(safe(w.body_fat_pct)))}</td><td>${Trainw.escapeHTML(safe(w.notes,''))}</td></tr>`).join('')}</tbody></table>`:`<p class="empty-state">${t('noData')}</p>`}
function renderGoals(){if(currentGoal){const days=currentGoal.target_date?Math.ceil((new Date(currentGoal.target_date)-new Date())/86400000):null;$('#goal-card-view').innerHTML=`<div class="goal-card"><div class="goal-grid"><div class="goal-item"><div class="goal-item-label">${t('goalType')}</div><div class="goal-item-value">${Trainw.escapeHTML(safe(currentGoal.goal_type))}</div></div><div class="goal-item"><div class="goal-item-label">${t('targetWeight')}</div><div class="goal-item-value">${Trainw.escapeHTML(String(safe(currentGoal.target_weight_kg)))}</div></div><div class="goal-item"><div class="goal-item-label">${t('targetDate')}</div><div class="goal-item-value">${Trainw.escapeHTML(fmtDate(currentGoal.target_date))}</div></div><div class="goal-item"><div class="goal-item-label">${t('goalDays')}</div><div class="goal-item-value">${Trainw.escapeHTML(days===null?'-':String(days))}</div></div></div><div style="margin-top:14px;color:var(--mt);">${Trainw.escapeHTML(safe(currentGoal.notes,''))}</div></div>`;$('#goal-type-input').value=currentGoal.goal_type||'general';$('#goal-target-weight').value=currentGoal.target_weight_kg||'';$('#goal-date-input').value=currentGoal.target_date||'';$('#goal-notes-input').value=currentGoal.notes||''}else $('#goal-card-view').innerHTML=`<p class="empty-state">${t('noGoal')}</p>`}
function renderCheckins(){const today=Trainw.dateOnly(new Date()),seen=new Set(checkins.map(c=>String(c.checked_in_at).slice(0,10)));$('#client-checkin-list').innerHTML=checkins.length?checkins.slice(0,30).map(c=>`<div class="checkin-list-item"><div><div class="activity-title">${Trainw.escapeHTML(fmtDate(c.checked_in_at))}</div><div class="activity-meta">${Trainw.escapeHTML(String(c.method||'manual'))}</div></div><div class="client-pill">OK</div></div>`).join(''):`<p class="empty-state">${t('noData')}</p>`;$('#client-checkin-heatmap').innerHTML=Array.from({length:35},(_,i)=>{const dte=Trainw.addDays(new Date(),-(34-i)),key=Trainw.dateOnly(dte);const cls=['heatmap-cell',seen.has(key)?'hit':'',key===today?'today':''].filter(Boolean).join(' ');return `<div class="${cls}" title="${Trainw.escapeHTML(key)}"></div>`}).join('')}
function renderMessages(){const badge=$('#client-msg-badge'),unread=threads.reduce((n,tg)=>n+tg.messages.filter(m=>m.receiver_id===currentUserId&&!m.is_read).length,0);badge.textContent=String(unread);badge.classList.toggle('hidden',!unread);$('#client-thread-list').innerHTML=threads.length?threads.map(th=>{const last=th.messages[th.messages.length-1];return `<div class="thread-item ${activeThreadId===th.id?'active':''}" data-thread="${th.id}"><div class="thread-item-name">${Trainw.escapeHTML(th.name)}</div><div class="thread-item-sub">${Trainw.escapeHTML(th.role)}</div><div class="thread-item-sub">${Trainw.escapeHTML(last?.content||'')}</div></div>`}).join(''):`<p class="empty-state">${t('noMessages')}</p>`;if(!activeThreadId&&threads[0])openThread(threads[0].id)}
async function openThread(id){activeThreadId=id;renderMessages();const th=threads.find(x=>x.id===id);if(!th)return;$('#client-conv-empty').classList.add('hidden');$('#client-conv-wrap').classList.remove('hidden');$('#client-conv-header').innerHTML=`<strong>${Trainw.escapeHTML(th.name)}</strong><div class="activity-meta">${Trainw.escapeHTML(th.role)}</div>`;$('#client-conv-messages').innerHTML=th.messages.length?th.messages.map(m=>`<div class="thread-message ${m.sender_id===currentUserId?'mine':''}"><div>${Trainw.escapeHTML(m.content||'')}</div><div class="thread-message-meta">${Trainw.escapeHTML(fmtDateTime(m.created_at))}</div></div>`).join(''):`<p class="empty-state">${t('noMessages')}</p>`;await Trainw.api.run(sb.from('messages').update({is_read:true}).eq('receiver_id',currentUserId).eq('sender_id',id),{context:'mark messages read',fallback:null,silent:true});markThreadReadLocal(id);renderMessages()}
function renderProfileCoach(){if(coachInfo)$('#profile-coach-card').innerHTML=`<div class="profile-coach"><div class="profile-coach-avatar">${Trainw.escapeHTML(initials(coachInfo.name))}</div><div><div class="activity-title">${Trainw.escapeHTML(coachInfo.name)}</div><div class="activity-meta">${Trainw.escapeHTML(coachInfo.specialty||'')}</div><div class="activity-meta">${Trainw.escapeHTML(coachInfo.phone||'')}</div></div></div>`;else $('#profile-coach-card').innerHTML=`<p class="empty-state">${t('noData')}</p>`}
function renderProfileOverview(){const target=currentGoal?.target_weight_kg??null,weight=currentWeight(),planDays=planByDay();$('#profile-goal-card').innerHTML=currentGoal?`<div class="summary-stack"><div class="summary-line"><span class="summary-line-label">${Trainw.escapeHTML(t('goalType'))}</span><strong>${Trainw.escapeHTML(safe(currentGoal.goal_type))}</strong></div><div class="summary-line"><span class="summary-line-label">${Trainw.escapeHTML(t('targetWeight'))}</span><strong>${Trainw.escapeHTML(target===null?'â€”':`${target} kg`)}</strong></div><div class="summary-line"><span class="summary-line-label">${Trainw.escapeHTML(t('targetDate'))}</span><strong>${Trainw.escapeHTML(fmtDate(currentGoal.target_date))}</strong></div></div><div class="summary-note">${Trainw.escapeHTML(currentGoal.notes||'')}</div>`:`<p class="empty-state">${t('noGoal')}</p>`;$('#profile-progress-metrics').innerHTML=`<div class="mini-metric-grid"><div class="mini-metric-card"><span class="mini-metric-label">Weight</span><strong>${Trainw.escapeHTML(weight===null?'â€”':`${weight} kg`)}</strong></div><div class="mini-metric-card"><span class="mini-metric-label">Streak</span><strong>${Trainw.escapeHTML(`${streak(checkins)} ${t('days')}`)}</strong></div><div class="mini-metric-card"><span class="mini-metric-label">Weekly sessions</span><strong>${Trainw.escapeHTML(String(bookedThisWeek()))}</strong></div><div class="mini-metric-card"><span class="mini-metric-label">Monthly check-ins</span><strong>${Trainw.escapeHTML(String(monthlyCheckins()))}</strong></div></div>`;$('#profile-plan-card').innerHTML=activePlan?`<div class="summary-stack"><div class="summary-line"><span class="summary-line-label">Plan</span><strong>${Trainw.escapeHTML(activePlan.title||'Active plan')}</strong></div><div class="summary-line"><span class="summary-line-label">Goal</span><strong>${Trainw.escapeHTML(safe(activePlan.goal,'â€”'))}</strong></div><div class="summary-line"><span class="summary-line-label">Frequency</span><strong>${Trainw.escapeHTML(`${safe(activePlan.frequency_per_week,0)}/7`)}</strong></div><div class="summary-line"><span class="summary-line-label">Training days</span><strong>${Trainw.escapeHTML(String(planDays.length))}</strong></div></div><div class="summary-note">${Trainw.escapeHTML(activePlan.description||'Your coach can update this plan as your routine changes.')}</div>`:`<p class="empty-state">${t('noPlan')}</p>`}
function renderAll(){applyTranslations();$('#sidebar-client-name').textContent=safe(currentProfile?.name||currentProfile?.email||'Client');$('#profile-name').value=currentProfile?.name||'';$('#profile-phone').value=currentProfile?.phone||'';$('#profile-email').value=currentProfile?.email||'';$('#profile-membership').value=(clientProfile?.membership_tier||'basic').toUpperCase();renderDashboard();renderProgram();renderBookingComposer();renderPastSessions();renderWeight();renderGoals();renderCheckins();renderMessages();renderProfileCoach();renderProfileOverview();lucide.createIcons();applyClientLocaleFixes()}
function setReviewDraft(sessionId,patch){const current=reviewDrafts.get(sessionId)||{rating:0,comment:''};reviewDrafts.set(sessionId,{...current,...patch})}
async function bookSelectedSession(){if(!selectedBookingCoachId||!selectedBookingDate||!selectedBookingSlot){Trainw.ui.showToast(t('bookingNeedsSelection'),'info');return}if(selectedBookingDate<Trainw.dateOnly(new Date())){Trainw.ui.showToast(t('bookingNeedsSelection'),'info');return}if(!window.confirm(bookingConfirmCopy()))return;const notes=$('#booking-notes-input')?.value.trim()||null;setBtnBusy('#btn-book-session',true);try{const r=await Trainw.api.run(sb.rpc('book_coach_session',{p_coach_id:selectedBookingCoachId,p_session_date:selectedBookingDate,p_start_time:selectedBookingSlot,p_notes:notes}),{context:'book coach session',fallback:null});if(r.error)return;selectedBookingSlot='';$('#booking-notes-input').value='';Trainw.ui.showToast(t('bookingSaved'),'success');await runClientReload()}finally{setBtnBusy('#btn-book-session',false)}}
async function cancelSession(sessionId){if(!sessionId||!window.confirm(cancelConfirmCopy()))return;const r=await Trainw.api.run(sb.rpc('cancel_session_booking',{p_session_id:sessionId,p_reason:null}),{context:'cancel coach session',fallback:null});if(r.error)return;queueClientReload(120)}
async function submitSessionReview(sessionId){const textarea=$(`[data-review-comment="${sessionId}"]`);if(textarea)setReviewDraft(sessionId,{comment:textarea.value});const draft=reviewDrafts.get(sessionId)||{rating:0,comment:''};if(!draft.rating){Trainw.ui.showToast(t('reviewRatingLabel'),'info');return}const r=await Trainw.api.run(sb.rpc('leave_session_review',{p_session_id:sessionId,p_rating:draft.rating,p_comment:draft.comment?.trim()||null}),{context:'leave session review',fallback:null});if(r.error)return;reviewDrafts.delete(sessionId);Trainw.ui.showToast(t('reviewSaved'),'success');await loadData()}
async function saveWeight(){const weightVal=+($('#weight-input').value||0),fatVal=$('#bodyfat-input').value?+$('#bodyfat-input').value:null;if(!Number.isFinite(weightVal)||weightVal<=0){Trainw.ui.showToast(t('weightKg'),'info');return}if(fatVal!==null&&(!Number.isFinite(fatVal)||fatVal<0||fatVal>100)){Trainw.ui.showToast(t('bodyFatPct'),'info');return}setBtnBusy('#btn-save-weight',true);try{const r=await Trainw.api.run(sb.from('weight_logs').insert({client_id:currentUserId,gym_id:currentGymId,logged_by:currentUserId,weight_kg:weightVal,body_fat_pct:fatVal,notes:$('#weight-notes-input').value||null,logged_at:($('#weight-date-input').value||Trainw.dateOnly(new Date()))+'T12:00:00'}),{context:'save weight',fallback:null});if(r.error)return;Trainw.ui.showToast(t('weightSaved'),'success');await runClientReload()}finally{setBtnBusy('#btn-save-weight',false)}}
async function saveGoal(){const targetVal=$('#goal-target-weight').value?+$('#goal-target-weight').value:null;if(targetVal!==null&&(!Number.isFinite(targetVal)||targetVal<=0)){Trainw.ui.showToast(t('targetWeight'),'info');return}const payload={client_id:currentUserId,gym_id:currentGymId,goal_type:$('#goal-type-input').value||'general',target_weight_kg:targetVal,target_date:$('#goal-date-input').value||null,notes:$('#goal-notes-input').value||null};setBtnBusy('#btn-save-goal',true);try{const r=currentGoal?.id?await Trainw.api.run(sb.from('client_goals').update(payload).eq('id',currentGoal.id),{context:'update goal',fallback:null}):await Trainw.api.run(sb.from('client_goals').insert(payload),{context:'insert goal',fallback:null});if(r.error)return;Trainw.ui.showToast(t('goalSaved'),'success');await runClientReload()}finally{setBtnBusy('#btn-save-goal',false)}}
async function submitCheckin(){const today=Trainw.dateOnly(new Date());if(checkins.some(c=>String(c.checked_in_at).slice(0,10)===today)){Trainw.ui.showToast(t('checkinAlready'),'info');return}setBtnBusy('#btn-client-checkin',true);try{const r=await Trainw.api.run(sb.from('check_ins').insert({client_id:currentUserId,gym_id:currentGymId,method:'manual'}),{context:'client checkin',fallback:null});if(r.error){if(r.error.code==='23505'){Trainw.ui.showToast(t('checkinAlready'),'info')}return}$('#client-checkin-feedback').textContent=t('checkinDone');$('#btn-client-checkin').classList.add('pulse-success');setTimeout(()=>$('#btn-client-checkin').classList.remove('pulse-success'),600);await runClientReload()}finally{setBtnBusy('#btn-client-checkin',false)}}
async function saveProfile(){const name=$('#profile-name').value.trim(),phone=$('#profile-phone').value.trim();if(!name){Trainw.ui.showToast(t('nameLabel'),'info');return}setBtnBusy('#btn-save-profile',true);try{const r=await Trainw.api.run(sb.from('users').update({name,phone:phone||null,language_preference:currentLang}).eq('id',currentUserId),{context:'save client profile',fallback:null});if(r.error)return;Trainw.ui.showToast(t('profileSaved'),'success');currentProfile.name=name;currentProfile.phone=phone;renderAll()}finally{setBtnBusy('#btn-save-profile',false)}}
async function sendClientMessage(){const thread=threads.find(x=>x.id===activeThreadId),content=$('#client-msg-input').value.trim();if(!thread||!content)return;setBtnBusy('#btn-send-client-message',true);try{const r=await Trainw.api.run(sb.from('messages').insert({sender_id:currentUserId,receiver_id:thread.id,gym_id:currentGymId,content}),{context:'send client message',fallback:null});if(r.error)return;$('#client-msg-input').value='';Trainw.ui.showToast(t('messageSent'),'success');queueClientReload(120)}finally{setBtnBusy('#btn-send-client-message',false)}}
function todayWorkoutSets(){const todays=planExercises.filter(x=>weekdayMatch(x.day_label));const flat=[];todays.forEach(ex=>{const total=Number(ex.sets||0);for(let i=1;i<=total;i+=1)flat.push({exercise:ex,setNumber:i,totalSets:total})});return flat}
function beep(){try{const a=new(window.AudioContext||window.webkitAudioContext)(),o=a.createOscillator(),g=a.createGain();o.connect(g);g.connect(a.destination);o.type='sine';o.frequency.value=880;g.gain.value=.06;o.start();o.stop(a.currentTime+.12)}catch(e){}}
function startWorkout(){const sets=todayWorkoutSets();if(!sets.length){Trainw.ui.showToast(t('noWorkoutToday'),'info');return}activeWorkout={startedAt:Date.now(),sets,index:0,results:[],restTimer:null};$('#active-workout-backdrop').classList.remove('hidden');$('#active-workout-overlay').classList.remove('hidden');$('#workout-summary').classList.add('hidden');renderWorkoutStep()}
function currentSet(){return activeWorkout?.sets?.[activeWorkout.index]||null}
function renderWorkoutStep(){const step=currentSet();if(!step){const mins=Math.max(1,Math.round((Date.now()-activeWorkout.startedAt)/60000));$('#workout-step-copy').textContent=t('workoutSummary');$('#workout-exercise-name').textContent=t('workoutSummary');$('#workout-exercise-target').textContent=`${activeWorkout.results.length} sets Â· ${mins} min`;$('#workout-rest-timer').textContent='';$('#workout-summary').classList.remove('hidden');$('#workout-summary-copy').textContent=activeWorkout.results.map(r=>r.exercise_name+' '+r.reps_done+'x'+r.weight_kg).join(' Â· ');return}$('#workout-summary').classList.add('hidden');$('#workout-step-copy').textContent=`${activeWorkout.index+1}/${activeWorkout.sets.length}`;$('#workout-exercise-name').textContent=step.exercise.exercise_name;$('#workout-exercise-target').textContent=`Set ${step.setNumber}/${step.totalSets} Â· ${safe(step.exercise.reps)} reps Â· ${safe(step.exercise.rest_seconds,0)}s rest`;$('#workout-rest-timer').textContent=String(safe(step.exercise.rest_seconds,0));$('#workout-reps-input').value='';$('#workout-weight-input').value=''}
function runRest(sec){clearInterval(activeWorkout.restTimer);let left=sec||0;$('#workout-rest-timer').textContent=String(left);activeWorkout.restTimer=setInterval(()=>{left=Math.max(0,left-1);$('#workout-rest-timer').textContent=String(left);if(left<=3&&left>0)beep();if(left===0)clearInterval(activeWorkout.restTimer)},1000)}
function completeSet(){const step=currentSet();if(!step)return;activeWorkout.results.push({exercise_name:step.exercise.exercise_name,set_number:step.setNumber,reps_done:+($('#workout-reps-input').value||step.exercise.reps||0),weight_kg:+($('#workout-weight-input').value||0),notes:null});activeWorkout.index+=1;if(currentSet())runRest(Number(step.exercise.rest_seconds||0));renderWorkoutStep()}
async function finishWorkout(){const mins=Math.max(1,Math.round((Date.now()-activeWorkout.startedAt)/60000));const logRes=await Trainw.api.run(sb.from('workout_logs').insert({client_id:currentUserId,gym_id:currentGymId,plan_id:activePlan?.id||null,logged_by:currentUserId,duration_minutes:mins,notes:$('#workout-notes-input').value||null,perceived_effort:+($('#workout-effort-input').value||6)}).select('id').maybeSingle(),{context:'save workout log',fallback:null});if(logRes.error||!logRes.data?.id)return;const setRes=await Trainw.api.run(sb.from('workout_log_sets').insert(activeWorkout.results.map(r=>({...r,log_id:logRes.data.id}))),{context:'save workout sets',fallback:null});if(setRes.error)return;Trainw.ui.showToast(t('workoutSaved'),'success');closeWorkout();await loadData()}
function closeWorkout(){clearInterval(activeWorkout?.restTimer);activeWorkout=null;$('#active-workout-backdrop').classList.add('hidden');$('#active-workout-overlay').classList.add('hidden')}
function randomGateTokenSegment(){const bytes=new Uint8Array(12);crypto.getRandomValues(bytes);return Array.from(bytes,byte=>byte.toString(16).padStart(2,'0')).join('')}
function clearGateCountdownTimer(){if(gateQrCountdownTimer){clearInterval(gateQrCountdownTimer);gateQrCountdownTimer=null}}
function updateGateCountdownLabel(){const el=$('#gate-qr-countdown'),c=$('#gate-qr-container');if(!el||!c)return;const key=c.dataset.emptyKey;if(key==='gateAccessNoGym')return el.textContent=t('gateAccessNoGym');if(key==='gateAccessError')return el.textContent=t('gateAccessUnavailable');if(key==='gateAccessLoading')return el.textContent=t('gateAccessLoading');if(!gateQrToken)return el.textContent=t('gateAccessUnavailable');el.textContent=t('gateAccessRefresh').replace('{seconds}',String(gateQrCountdownValue))}
function renderGateQrPlaceholder(key){const c=$('#gate-qr-container');if(!c)return;c.dataset.emptyKey=key;c.innerHTML=`<div class="gate-qr-empty">${Trainw.escapeHTML(t(key))}</div>`;gateQrToken='';updateGateCountdownLabel()}
function renderGateQr(token){const c=$('#gate-qr-container');if(!c||typeof QRCode==='undefined')return;c.dataset.emptyKey='';c.innerHTML='';new QRCode(c,{text:token,width:180,height:180,colorDark:'#000000',colorLight:'#ffffff',correctLevel:QRCode.CorrectLevel.M});gateQrToken=token;updateGateCountdownLabel()}
function startGateCountdown(){clearGateCountdownTimer();gateQrCountdownValue=55;updateGateCountdownLabel();gateQrCountdownTimer=setInterval(()=>{gateQrCountdownValue=Math.max(0,gateQrCountdownValue-1);updateGateCountdownLabel();if(gateQrCountdownValue<=0)clearGateCountdownTimer()},1000)}
async function refreshGateQR(){if(!currentGymId)await inferClientGymId();if(!currentGymId){renderGateQrPlaceholder('gateAccessNoGym');return}renderGateQrPlaceholder('gateAccessLoading');const token=`${currentUserId}.${currentGymId}.${Date.now()}.${randomGateTokenSegment()}`;const r=await Trainw.api.run(sb.from('gate_sessions').insert({client_id:currentUserId,gym_id:currentGymId,token,expires_at:new Date(Date.now()+60000).toISOString(),used:false}),{context:'create gate session',fallback:null});if(r.error)return renderGateQrPlaceholder('gateAccessError');renderGateQr(token);startGateCountdown()}
async function initGateQR(){if(gateQrInitialized)return;gateQrInitialized=true;await refreshGateQR();gateQrRefreshTimer=setInterval(()=>refreshGateQR(),55000)}
async function bootstrap(){const ctx=await Trainw.auth.getContext(sb,{expectedRoles:['client'],loginHref:LOGIN_HREF,recoveryRole:'client'});if(!ctx.session||!ctx.profile)return;currentProfile=ctx.profile;currentUserId=ctx.session.user.id;currentGymId=ctx.profile.gym_id||null;currentLang=localStorage.getItem('trainw_lang')||ctx.profile.language_preference||currentLang;applyTranslations();bindClientLocaleObserver();await inferClientGymId();if(!currentGymId){mySessions=[];availableCoaches=[];bookingSlots=[];activePlan=null;planExercises=[];workoutLogs=[];weightLogs=[];currentGoal=null;checkins=[];threads=[];reviewsBySession=new Map();renderAll();await initGateQR();if(!window.__clientAuthBound){window.__clientAuthBound=true;Trainw.auth.watchAuth(sb,{onSignedOut:()=>{localStorage.removeItem('trainw_active_gym');window.location.href=LOGIN_HREF}})}return}await loadData();await initGateQR();subscribeClientRealtime();if(!window.__clientUnloadBound){window.__clientUnloadBound=true;window.addEventListener('beforeunload',()=>{clearClientRealtime();clearTimeout(clientReloadTimer);if(gateQrRefreshTimer){clearInterval(gateQrRefreshTimer);gateQrRefreshTimer=null}clearGateCountdownTimer()})}if(!window.__clientAuthBound){window.__clientAuthBound=true;Trainw.auth.watchAuth(sb,{onSignedOut:()=>{localStorage.removeItem('trainw_active_gym');window.location.href=LOGIN_HREF}})}}
$$('.nav-item').forEach(n=>n.addEventListener('click',()=>showPage(n.dataset.page)));
$$('.lang-btn').forEach(b=>b.addEventListener('click',()=>{currentLang=b.dataset.lang;localStorage.setItem('trainw_lang',currentLang);renderAll();updateGateCountdownLabel()}));
document.body.addEventListener('click',event=>{const trigger=event.target.closest('[data-open-page]');if(trigger)showPage(trigger.dataset.openPage)});
$('#booking-coach-search').addEventListener('input',renderBookingComposer);
$('#booking-date-input').addEventListener('change',async e=>{selectedBookingDate=e.target.value;selectedBookingSlot='';await loadBookingSlots();renderBookingComposer();renderDashboardBookingSummary()});
$('#booking-coach-list').addEventListener('click',async e=>{const card=e.target.closest('[data-book-coach]');if(!card)return;selectedBookingCoachId=card.dataset.bookCoach;selectedBookingSlot='';await loadBookingSlots();renderBookingComposer();renderDashboardBookingSummary()});
$('#booking-calendar-grid').addEventListener('click',async e=>{const dayCard=e.target.closest('[data-book-date]');if(!dayCard)return;selectedBookingDate=dayCard.dataset.bookDate;selectedBookingSlot='';$('#booking-date-input').value=selectedBookingDate;await loadBookingSlots();renderBookingComposer();renderDashboardBookingSummary()});
$('#booking-slot-list').addEventListener('click',e=>{const slot=e.target.closest('[data-slot-time]');if(!slot)return;selectedBookingSlot=slot.dataset.slotTime;renderBookingComposer();renderDashboardBookingSummary()});
$('#booking-notes-input').addEventListener('input',renderBookingConfirmation);
$('#btn-book-session').addEventListener('click',bookSelectedSession);
$('#dashboard-upcoming-list').addEventListener('click',e=>{const cancel=e.target.closest('[data-cancel-session]');if(cancel)cancelSession(cancel.dataset.cancelSession)});
$('#client-past-sessions-list').addEventListener('click',e=>{const star=e.target.closest('[data-review-rating]');if(star){setReviewDraft(star.dataset.reviewSession,{rating:+star.dataset.reviewRating||0});renderPastSessions();return}const submit=e.target.closest('[data-review-submit]');if(submit)submitSessionReview(submit.dataset.reviewSubmit)});
$('#client-past-sessions-list').addEventListener('input',e=>{const area=e.target.closest('[data-review-comment]');if(area)setReviewDraft(area.dataset.reviewComment,{comment:area.value})});
$('#btn-save-weight').addEventListener('click',saveWeight);
$('#toggle-bodyfat').addEventListener('change',renderWeight);
$('#btn-save-goal').addEventListener('click',saveGoal);
$('#btn-client-checkin').addEventListener('click',submitCheckin);
$('#btn-save-profile').addEventListener('click',saveProfile);
$('#btn-reset-password').addEventListener('click',async()=>{setBtnBusy('#btn-reset-password',true);try{const r=await Trainw.api.run(sb.auth.resetPasswordForEmail(currentProfile.email),{context:'client reset password',fallback:null,toastOnError:false});if(r.error)return;Trainw.ui.showToast(t('passwordResetSent'),'success')}finally{setBtnBusy('#btn-reset-password',false)}});
$('#btn-send-client-message').addEventListener('click',sendClientMessage);
$('#client-msg-input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendClientMessage()}});
$('#client-thread-list').addEventListener('click',e=>{const thread=e.target.closest('[data-thread]');if(thread)openThread(thread.dataset.thread)});
$('#program-accordion').addEventListener('click',e=>{const toggle=e.target.closest('[data-toggle-day]');if(toggle)toggle.closest('.program-day-card')?.classList.toggle('open')});
$('#btn-start-workout').addEventListener('click',startWorkout);
$('#btn-close-workout').addEventListener('click',closeWorkout);
$('#btn-complete-set').addEventListener('click',completeSet);
$('#btn-finish-workout').addEventListener('click',finishWorkout);
$('#btn-logout').addEventListener('click',async()=>{clearClientRealtime();clearTimeout(clientReloadTimer);if(gateQrRefreshTimer){clearInterval(gateQrRefreshTimer);gateQrRefreshTimer=null}clearGateCountdownTimer();await sb.auth.signOut({scope:'global'});localStorage.removeItem('trainw_active_gym');window.location.href=LOGIN_HREF});
bootstrap();



